#!/usr/bin/env bash
# Regenerate the Python gRPC stubs for the OSCAL bridge from the canonical
# proto at proto/oscal/v1/oscal.proto.
#
# The Go bindings are generated by `buf generate` (see buf.gen.yaml); the
# Python bindings are generated here because grpcio-tools is a Python-only
# toolchain. Both derive from the SAME proto file — the proto is the
# single source of truth for the Go <-> Python contract.
#
# grpc_tools.protoc emits `import oscal_pb2` (a top-level import). Inside
# our package that must be a package-relative import, so we post-process
# the one line. This is the documented, standard workaround for
# grpcio-tools' lack of a relative-import flag.
#
# Run from the repo root:  bash oscal-bridge/scripts/gen_proto.sh
# Requires: a Python env with grpcio-tools (e.g. `uv sync` in oscal-bridge).
set -euo pipefail

REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
cd "$REPO_ROOT"

PKG_DIR="oscal-bridge/atlas_oscal_bridge"
PROTO_SRC="proto/oscal/v1/oscal.proto"

# protoc resolves imports relative to -I; we point it at the dir holding
# oscal.proto so the generated module name is a flat `oscal_pb2`.
TMP_PROTO_DIR="$(mktemp -d)"
trap 'rm -rf "$TMP_PROTO_DIR"' EXIT
cp "$PROTO_SRC" "$TMP_PROTO_DIR/oscal.proto"

python -m grpc_tools.protoc \
  -I"$TMP_PROTO_DIR" \
  --python_out="$PKG_DIR" \
  --grpc_python_out="$PKG_DIR" \
  "$TMP_PROTO_DIR/oscal.proto"

# Patch the grpc stub's top-level import to a package-relative one.
python - "$PKG_DIR/oscal_pb2_grpc.py" <<'PYEOF'
import sys, pathlib
p = pathlib.Path(sys.argv[1])
text = p.read_text()
text = text.replace(
    "import oscal_pb2 as oscal__pb2",
    "from . import oscal_pb2 as oscal__pb2",
)
p.write_text(text)
print(f"patched relative import in {p}")
PYEOF

echo "oscal-bridge: Python gRPC stubs regenerated from $PROTO_SRC"
